import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CompetitorPrice {
  store: string;
  price: number;
}

interface Product {
  name: string;
  currentPrice: number;
  competitorPrices: CompetitorPrice[];
}

interface PriceTrend {
  dates: string[];
  prices: number[];
}

interface WidgetData {
  product: Product;
  priceTrend: PriceTrend;
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { product, priceTrend } = widgetData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              {product.name}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#10B981' }}>
              ${product.currentPrice.toFixed(2)}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Competitor Prices
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {product.competitorPrices.map((competitor) => (
                <Chip
                  key={competitor.store}
                  label={`${competitor.store}: $${competitor.price.toFixed(2)}`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: priceTrend.prices,
                  color: '#FFC107',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: priceTrend.dates,
                  id: 'dates',
                },
              ]}
              yAxis={[{ id: 'prices' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="dates"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="prices"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
